26528   /// Creates the reduction from the given \p Vec vector value with the given
26529   /// scale \p Scale and signedness \p IsSigned.
26530   Value *createSingleOp(IRBuilderBase &Builder, const TargetTransformInfo &TTI,
26531                         Value *Vec, unsigned Scale, bool IsSigned, Type *DestTy,
26532                         bool ReducedInTree) {
26533     Value *Rdx;
26534     if (ReducedInTree) {
26535       Rdx = Vec;
26536     } else if (auto *VecTy = dyn_cast<FixedVectorType>(DestTy)) {
26537       unsigned DestTyNumElements = getNumElements(VecTy);
26538       unsigned VF = getNumElements(Vec->getType()) / DestTyNumElements;
26539       Rdx = PoisonValue::get(
26540           getWidenedType(Vec->getType()->getScalarType(), DestTyNumElements));
26541       for (unsigned I : seq<unsigned>(DestTyNumElements)) {
26542         // Do reduction for each lane.
26543         // e.g., do reduce add for
26544         // VL[0] = <4 x Ty> <a, b, c, d>
26545         // VL[1] = <4 x Ty> <e, f, g, h>
26546         // Lane[0] = <2 x Ty> <a, e>
26547         // Lane[1] = <2 x Ty> <b, f>
26548         // Lane[2] = <2 x Ty> <c, g>
26549         // Lane[3] = <2 x Ty> <d, h>
26550         // result[0] = reduce add Lane[0]
26551         // result[1] = reduce add Lane[1]
26552         // result[2] = reduce add Lane[2]
26553         // result[3] = reduce add Lane[3]
26554         SmallVector<int, 16> Mask = createStrideMask(I, DestTyNumElements, VF);
26555         Value *Lane = Builder.CreateShuffleVector(Vec, Mask);
26556         Rdx = Builder.CreateInsertElement(
26557             Rdx, emitReduction(Lane, Builder, &TTI, DestTy), I);
26558       }
26559     } else {
26560       Rdx = emitReduction(Vec, Builder, &TTI, DestTy);
26561     }
26562     if (Rdx->getType() != DestTy)
26563       Rdx = Builder.CreateIntCast(Rdx, DestTy, IsSigned);
26564     // Improved analysis for add/fadd/xor reductions with same scale
26565     // factor for all operands of reductions. We can emit scalar ops for
26566     // them instead.
26567     if (Scale > 1)
26568       Rdx = emitScaleForReusedOps(Rdx, Builder, Scale);
26569     return Rdx;
26570   }
